+          mechanismFrequency[mechanism] = (mechanismFrequency[mechanism] || 0) + 1;
+        }
+      });
+
+      const bestMechanism = Object.entries(mechanismFrequency)
+        .sort(([, a], [, b]) => b - a)[0]?.[0] as AttentionMechanism;
+
+      if (bestMechanism) {
+        console.log(`Historical preference: ${bestMechanism}`);
