+/**
+ * Find code files in directory
+ */
+function findCodeFiles(
+  dir: string,
+  extensions: string[],
+  maxFiles: number
+): Array<{ path: string; language: string; content: string }> {
+  const files: any[] = [];
+
+  function scan(currentDir: string) {
+    if (files.length >= maxFiles) return;
+
+    const entries = readdirSync(currentDir);
+
+    for (const entry of entries) {
+      if (files.length >= maxFiles) break;
+
+      const fullPath = join(currentDir, entry);
+      const stat = statSync(fullPath);
+
+      if (stat.isDirectory()) {
+        if (!entry.startsWith('.') && entry !== 'node_modules') {
+          scan(fullPath);
+        }
+      } else {
+        const ext = extname(entry).slice(1);
+        if (extensions.includes(ext)) {
+          try {
+            const content = readFileSync(fullPath, 'utf8');
+            files.push({
+              path: fullPath,
+              language: ext,
+              content
+            });
+          } catch (error) {
+            // Skip unreadable files
+          }
+        }
+      }
+    }
+  }
+
+  scan(dir);
+  return files;
+}
+
+/**
+ * Mock embedding (replace with actual embedding service)
+ */
+function mockEmbedding(text: string): number[] {
+  const hash = text.split('').reduce((acc, char) => {
+    return ((acc << 5) - acc) + char.charCodeAt(0);
+  }, 0);
+
+  const embedding = new Array(3072);
+  for (let i = 0; i < 3072; i++) {
+    const seed = hash + i;
+    embedding[i] = (Math.sin(seed) * 10000) - Math.floor(Math.sin(seed) * 10000);
+  }
+
+  return embedding;
+}

